// ════════════════════════════════════════════════════════════
//  CONTROL DATA FUNCTIONS
// ════════════════════════════════════════════════════════════

function getISO27001Controls() {
  const raw=[
    ["5.1","Policies for information security","5","Policies for information security shall be defined, approved by management, published, communicated to and acknowledged by relevant personnel, and reviewed at planned intervals or if significant changes occur.","[EXAMINE]: Information security policy; approval records; distribution evidence. [INTERVIEW]: Management. [TEST]: Policy review cycle."],
    ["5.2","Information security roles and responsibilities","5","All information security responsibilities shall be defined and allocated according to the organization's information security policy topics.","[EXAMINE]: RACI; job descriptions; role assignments. [INTERVIEW]: Security personnel."],
    ["5.3","Segregation of duties","5","Conflicting duties and conflicting areas of responsibility shall be segregated.","[EXAMINE]: Role definitions; access matrix. [TEST]: Access separation controls."],
    ["5.4","Management responsibilities","5","Management shall require all personnel to apply information security in accordance with the established information security policy, topic-specific policies and procedures.","[EXAMINE]: Management directives; acknowledgments. [INTERVIEW]: Management."],
    ["5.5","Contact with authorities","5","The organization shall establish and maintain contact with relevant authorities.","[EXAMINE]: Contact lists; incident reporting procedures; regulatory liaison records."],
    ["5.6","Contact with special interest groups","5","The organization shall establish and maintain contact with special interest groups or other specialist security forums and professional associations.","[EXAMINE]: Memberships; threat intelligence feeds; forum participation."],
    ["5.7","Threat intelligence","5","Information relating to information security threats shall be collected and analysed to produce threat intelligence.","[EXAMINE]: Threat intel feeds; analysis reports. [TEST]: Integration with controls."],
    ["5.8","Information security in project management","5","Information security shall be integrated into project management.","[EXAMINE]: Project methodology; security checklists; project security reviews."],
    ["5.9","Inventory of information and other associated assets","5","An inventory of information and other associated assets, including owners, shall be developed and maintained.","[EXAMINE]: Asset inventory; ownership assignments. [TEST]: Inventory completeness."],
    ["5.10","Acceptable use of information and other associated assets","5","Rules for the acceptable use and procedures for handling information and other associated assets shall be identified, documented and implemented.","[EXAMINE]: AUP; user acknowledgments."],
    ["5.11","Return of assets","5","Personnel shall return all organizational assets upon termination of employment, contract or agreement.","[EXAMINE]: Offboarding procedures; asset return checklists."],
    ["5.12","Classification of information","5","Information shall be classified according to the information security needs of the organization based on confidentiality, integrity, availability.","[EXAMINE]: Classification scheme; guidelines; classified asset samples."],
    ["5.13","Labelling of information","5","An appropriate set of procedures for information labelling shall be developed and implemented in accordance with the information classification scheme.","[EXAMINE]: Labelling procedures; labelled samples. [TEST]: Labelling enforcement."],
    ["5.14","Information transfer","5","Information transfer rules, procedures, or agreements shall be in place for all types of transfer facilities within and between organizations.","[EXAMINE]: Transfer policies; data sharing agreements; NDA templates."],
    ["5.15","Access control","5","Rules to control physical and logical access to information and other associated assets shall be established and implemented based on business requirements.","[EXAMINE]: Access control policy; rights matrix. [TEST]: Access enforcement."],
    ["5.16","Identity management","5","The full life cycle of identities shall be managed.","[EXAMINE]: Identity lifecycle procedures; provisioning/deprovisioning records. [TEST]: IAM system configuration."],
    ["5.17","Authentication information","5","Allocation and management of authentication information shall be controlled by a management process.","[EXAMINE]: Password/authenticator policy. [TEST]: Authentication controls."],
    ["5.18","Access rights","5","Access rights to information and other associated assets shall be provisioned, reviewed, modified and removed in accordance with the access control policy.","[EXAMINE]: Access provisioning procedures; review records. [TEST]: Rights alignment."],
    ["5.19","Information security in supplier relationships","5","Processes and procedures shall be defined and implemented to manage information security risks associated with the use of supplier products or services.","[EXAMINE]: Supplier security policy; contracts; risk assessments."],
    ["5.20","Addressing information security within supplier agreements","5","Relevant information security requirements shall be established and agreed with each supplier based on the type of supplier relationship.","[EXAMINE]: Supplier contracts; security clauses; SLAs."],
    ["5.21","Managing information security in the ICT supply chain","5","Processes and procedures shall be defined and implemented to manage information security risks associated with the ICT products and services supply chain.","[EXAMINE]: Supply chain risk management procedures; supplier assessments."],
    ["5.22","Monitoring, review and change management of supplier services","5","The organization shall regularly monitor, review, evaluate and manage change in supplier information security practices and service delivery.","[EXAMINE]: Supplier monitoring records; review reports; change management."],
    ["5.23","Information security for use of cloud services","5","Processes for acquisition, use, management and exit from cloud services shall be established in accordance with the organization's information security requirements.","[EXAMINE]: Cloud security policy; cloud agreements; exit procedures. [TEST]: Cloud controls."],
    ["5.24","Information security incident management planning and preparation","5","The organization shall plan and prepare for managing information security incidents by defining, establishing and communicating incident management processes, roles and responsibilities.","[EXAMINE]: Incident management plan; roles; communication procedures."],
    ["5.25","Assessment and decision on information security events","5","The organization shall assess information security events and decide if they are to be categorized as information security incidents.","[EXAMINE]: Event assessment criteria; triage procedures; categorization records."],
    ["5.26","Response to information security incidents","5","Information security incidents shall be responded to in accordance with the documented procedures.","[EXAMINE]: Incident response procedures; incident records; post-incident reviews."],
    ["5.27","Learning from information security incidents","5","Knowledge gained from information security incidents shall be used to strengthen and improve information security controls.","[EXAMINE]: Lessons learned; control improvements; post-incident reports."],
    ["5.28","Collection of evidence","5","The organization shall establish and implement procedures for identification, collection, acquisition and preservation of evidence related to information security events.","[EXAMINE]: Evidence collection procedures; chain of custody; forensic capability."],
    ["5.29","Information security during disruption","5","The organization shall plan how to maintain information security at an appropriate level during disruption.","[EXAMINE]: BC plans; information security continuity procedures; BIA."],
    ["5.30","ICT readiness for business continuity","5","ICT readiness shall be planned, implemented, maintained and tested based on business continuity objectives and ICT continuity requirements.","[EXAMINE]: ICT continuity plans; RTO/RPO documentation; continuity tests."],
    ["5.31","Legal, statutory, regulatory and contractual requirements","5","Legal, statutory, regulatory and contractual requirements relevant to information security shall be identified, documented and kept up to date.","[EXAMINE]: Legal register; compliance matrix; regulatory monitoring."],
    ["5.32","Intellectual property rights","5","The organization shall implement appropriate procedures to protect intellectual property rights.","[EXAMINE]: IP policy; software licensing records; copyright procedures."],
    ["5.33","Protection of records","5","Records shall be protected from loss, destruction, falsification, unauthorized access and unauthorized release.","[EXAMINE]: Records management policy; retention schedules; access controls."],
    ["5.34","Privacy and protection of PII","5","The organization shall identify and meet requirements regarding the preservation of privacy and protection of PII according to applicable laws and regulations.","[EXAMINE]: Privacy policy; PII inventory; DPIA records; consent mechanisms."],
    ["5.35","Independent review of information security","5","The organization's approach to managing information security shall be reviewed independently at planned intervals or when significant changes occur.","[EXAMINE]: Internal audit reports; independent review records; management review minutes."],
    ["5.36","Compliance with policies, rules and standards for information security","5","Compliance with the organization's information security policy, topic-specific policies, rules and standards shall be regularly reviewed.","[EXAMINE]: Compliance review records; audit findings; corrective actions."],
    ["5.37","Documented operating procedures","5","Operating procedures for information processing facilities shall be documented and made available to personnel who need them.","[EXAMINE]: Procedure inventory; documented SOPs; change control."],
    ["6.1","Screening","6","Background verification checks on all candidates to become personnel shall be carried out prior to joining the organization and on an ongoing basis.","[EXAMINE]: Background check policy; screening records; verification evidence."],
    ["6.2","Terms and conditions of employment","6","The employment contractual agreements shall state the personnel's and the organization's responsibilities for information security.","[EXAMINE]: Employment contracts; security clauses; signed acknowledgments."],
    ["6.3","Information security awareness, education and training","6","Personnel shall receive appropriate information security awareness education and training and regular updates relevant for their job function.","[EXAMINE]: Training programme; completion records; awareness materials."],
    ["6.4","Disciplinary process","6","A disciplinary process shall be formalized and communicated to take action against personnel who have committed an information security policy violation.","[EXAMINE]: Disciplinary policy; HR procedures; disciplinary records."],
    ["6.5","Responsibilities after termination or change of employment","6","Information security responsibilities and duties that remain valid after termination or change of employment shall be defined, enforced and communicated.","[EXAMINE]: Offboarding procedures; post-employment obligations; NDA terms."],
    ["6.6","Confidentiality or non-disclosure agreements","6","Confidentiality or non-disclosure agreements reflecting the organization's needs for the protection of information shall be identified, documented, regularly reviewed and signed.","[EXAMINE]: NDA templates; signed NDA records; review cycle documentation."],
    ["6.7","Remote working","6","Security measures shall be implemented when personnel are working remotely to protect information accessed, processed or stored outside the organization's premises.","[EXAMINE]: Remote working policy; VPN; endpoint controls. [TEST]: Remote access security."],
    ["6.8","Information security event reporting","6","The organization shall provide a mechanism for personnel to report observed or suspected information security events through appropriate channels in a timely manner.","[EXAMINE]: Reporting mechanism; channel availability; event log records."],
    ["7.1","Physical security perimeters","7","Security perimeters shall be defined and used to protect areas that contain information and other associated assets.","[EXAMINE]: Physical security policy; perimeter definition; site surveys. [TEST]: Perimeter control effectiveness."],
    ["7.2","Physical entry","7","Secure areas shall be protected by appropriate entry controls and access points.","[EXAMINE]: Access control records; visitor logs; entry point controls. [TEST]: Physical access control systems."],
    ["7.3","Securing offices, rooms and facilities","7","Physical security for offices, rooms and facilities shall be designed and implemented.","[EXAMINE]: Physical security design; facility inspection records; lock and key management."],
    ["7.4","Physical security monitoring","7","Premises shall be continuously monitored for unauthorized physical access.","[EXAMINE]: CCTV records; alarm systems; monitoring logs. [TEST]: Physical monitoring systems."],
    ["7.5","Protecting against physical and environmental threats","7","Protection against physical and environmental threats shall be designed and implemented.","[EXAMINE]: Environmental threat assessment; protection measures; facility risk assessment."],
    ["7.6","Working in secure areas","7","Security measures for working in secure areas shall be designed and implemented.","[EXAMINE]: Secure area procedures; clean desk policy; unsupervised access controls."],
    ["7.7","Clear desk and clear screen","7","Clear desk rules for papers and removable storage media and clear screen rules for information processing facilities shall be defined and appropriately enforced.","[EXAMINE]: Clear desk/screen policy; inspection records. [TEST]: Policy enforcement."],
    ["7.8","Equipment siting and protection","7","Equipment shall be sited securely and protected.","[EXAMINE]: Equipment placement records; environmental controls; physical protection."],
    ["7.9","Security of assets off-premises","7","Off-premises assets shall be protected.","[EXAMINE]: Off-premises asset policy; asset tracking; mobile device controls."],
    ["7.10","Storage media","7","Storage media shall be managed through its life cycle of acquisition, use, transportation and disposal in accordance with the organization's classification scheme.","[EXAMINE]: Media management policy; media inventory; disposal records."],
    ["7.11","Supporting utilities","7","Information processing facilities shall be protected from power failures and other disruptions caused by failures in supporting utilities.","[EXAMINE]: UPS documentation; generator records; contingency plans. [TEST]: UPS testing."],
    ["7.12","Cabling security","7","Cables carrying power, data or supporting information services shall be protected from interception, interference or damage.","[EXAMINE]: Cabling documentation; cable management; physical inspection records."],
    ["7.13","Equipment maintenance","7","Equipment shall be maintained correctly to ensure availability, integrity and confidentiality of information.","[EXAMINE]: Maintenance schedules; maintenance records; authorized maintainer lists."],
    ["7.14","Secure disposal or re-use of equipment","7","Items of equipment containing storage media shall be verified to ensure that any sensitive data has been removed or securely overwritten prior to disposal or re-use.","[EXAMINE]: Disposal procedures; sanitization records; certificates of destruction."],
    ["8.1","User endpoint devices","8","Information stored on, processed by or accessible via user endpoint devices shall be protected.","[EXAMINE]: Endpoint security policy; MDM configuration. [TEST]: Endpoint controls."],
    ["8.2","Privileged access rights","8","The allocation and use of privileged access rights shall be restricted and managed.","[EXAMINE]: Privileged access policy; account inventory; review records. [TEST]: PAM configuration."],
    ["8.3","Information access restriction","8","Access to information and other associated assets shall be restricted in accordance with the established access control policy.","[EXAMINE]: Access control configuration; user access rights. [TEST]: Access restriction."],
    ["8.4","Access to source code","8","Read and write access to source code, development tools and software libraries shall be appropriately managed.","[EXAMINE]: Source code access policy; repository rights. [TEST]: Repository access controls."],
    ["8.5","Secure authentication","8","Secure authentication technologies and procedures shall be implemented based on information access restrictions and the access control policy.","[EXAMINE]: Authentication policy; MFA records. [TEST]: Authentication mechanisms."],
    ["8.6","Capacity management","8","The use of resources shall be monitored and adjusted in line with current and expected capacity requirements.","[EXAMINE]: Capacity planning documentation; monitoring reports; scaling procedures."],
    ["8.7","Protection against malware","8","Protection against malware shall be implemented and supported by appropriate user awareness.","[EXAMINE]: Anti-malware policy; endpoint protection. [TEST]: Anti-malware coverage."],
    ["8.8","Management of technical vulnerabilities","8","Information about technical vulnerabilities shall be obtained, the organization's exposure evaluated and appropriate measures taken.","[EXAMINE]: Vulnerability management policy; scan results; patch records. [TEST]: Scanning config."],
    ["8.9","Configuration management","8","Configurations, including security configurations, of hardware, software, services and networks shall be established, documented, implemented, monitored and reviewed.","[EXAMINE]: Configuration baselines; STIG/CIS benchmarks. [TEST]: Configuration compliance."],
    ["8.10","Information deletion","8","Information stored in systems, devices or any other storage media shall be deleted when no longer required.","[EXAMINE]: Data deletion policy; deletion records; retention schedule alignment."],
    ["8.11","Data masking","8","Data masking shall be used in accordance with the organization's topic-specific policy on access control and other related policies, and business requirements.","[EXAMINE]: Data masking policy; masking implementation. [TEST]: Masking effectiveness."],
    ["8.12","Data leakage prevention","8","Data leakage prevention measures shall be applied to systems, networks and any other devices that process, store or transmit sensitive information.","[EXAMINE]: DLP policy; DLP tool deployment. [TEST]: DLP configuration."],
    ["8.13","Information backup","8","Backup copies of information, software and systems shall be maintained and regularly tested in accordance with the agreed backup policy.","[EXAMINE]: Backup policy; backup schedules; restore test records. [TEST]: Backup and restoration."],
    ["8.14","Redundancy of information processing facilities","8","Information processing facilities shall be implemented with redundancy sufficient to meet availability requirements.","[EXAMINE]: Redundancy architecture; failover test records; HA configuration."],
    ["8.15","Logging","8","Logs that record activities, exceptions, faults and other relevant events shall be produced, stored, protected and analysed.","[EXAMINE]: Logging policy; log configuration; retention records. [TEST]: Log completeness."],
    ["8.16","Monitoring activities","8","Networks, systems and applications shall be monitored for anomalous behaviour and appropriate actions taken to evaluate potential incidents.","[EXAMINE]: Monitoring strategy; SIEM configuration; alert records. [TEST]: Monitoring coverage."],
    ["8.17","Clock synchronisation","8","The clocks of information processing systems used by the organization shall be synchronized to approved time sources.","[EXAMINE]: NTP configuration; approved time sources. [TEST]: Clock synchronization."],
    ["8.18","Use of privileged utility programs","8","The use of utility programs that might be capable of overriding system and application controls shall be restricted and tightly controlled.","[EXAMINE]: Utility program inventory; access restrictions; usage logs."],
    ["8.19","Installation of software on operational systems","8","Procedures and measures shall be implemented to securely manage software installation on operational systems.","[EXAMINE]: Software installation policy; change approval; authorized software list."],
    ["8.20","Networks security","8","Networks and network devices shall be secured, managed and controlled to protect information in systems and applications.","[EXAMINE]: Network security policy; firewall rules; segmentation. [TEST]: Network controls."],
    ["8.21","Security of network services","8","Security mechanisms, service levels and service requirements of network services shall be identified, implemented and monitored.","[EXAMINE]: Network service agreements; security requirements; monitoring records."],
    ["8.22","Segregation of networks","8","Groups of information services, users and information systems shall be segregated in the organization's networks.","[EXAMINE]: Network architecture; VLAN configuration; segmentation policy. [TEST]: Segregation."],
    ["8.23","Web filtering","8","Access to external websites shall be managed to reduce exposure to malicious content.","[EXAMINE]: Web filtering policy; filtering tool deployment. [TEST]: Filtering configuration."],
    ["8.24","Use of cryptography","8","Rules for the effective use of cryptography, including cryptographic key management, shall be defined and implemented.","[EXAMINE]: Cryptography policy; encryption records; key management. [TEST]: Cryptographic controls."],
    ["8.25","Secure development life cycle","8","Rules for the secure development of software and systems shall be established and applied.","[EXAMINE]: Secure SDLC policy; development standards; security requirements."],
    ["8.26","Application security requirements","8","Information security requirements shall be identified, specified and approved when developing or acquiring applications.","[EXAMINE]: Security requirements documentation; application security standards."],
    ["8.27","Secure system architecture and engineering principles","8","Principles for engineering secure systems shall be established, documented, maintained and applied to any information system implementation.","[EXAMINE]: Security architecture principles; design documentation; architecture reviews."],
    ["8.28","Secure coding","8","Secure coding principles shall be applied to software development.","[EXAMINE]: Secure coding standards; code review records. [TEST]: SAST/DAST outputs."],
    ["8.29","Security testing in development and acceptance","8","Security testing processes shall be defined and implemented in the development life cycle.","[EXAMINE]: Security testing policy; pentest results; acceptance test records."],
    ["8.30","Outsourced development","8","The organization shall direct, monitor and review the activities related to outsourced system development.","[EXAMINE]: Outsourcing security requirements; vendor oversight; code review procedures."],
    ["8.31","Separation of development, test and production environments","8","Development, testing and production environments shall be separated and secured.","[EXAMINE]: Environment separation documentation; access controls. [TEST]: Environment isolation."],
    ["8.32","Change management","8","Changes to information processing facilities and information systems shall be subject to change management procedures.","[EXAMINE]: Change management policy; change request records; CAB minutes."],
    ["8.33","Test information","8","Test information shall be appropriately selected, protected and managed.","[EXAMINE]: Test data management policy; data masking in test environments."],
    ["8.34","Protection of information systems during audit testing","8","Audit tests and other assurance activities involving assessment of operational systems shall be planned and agreed between the tester and appropriate management.","[EXAMINE]: Audit planning documentation; authorization records; audit tool controls."],
  ];
  return raw.map(([id,name,theme,desc,proc])=>({id,name,group:theme,desc,proc}));
}

